import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
import { closeStudio, createAgentSession, isStudioBrowserConnected, navigateStudio, navigateStudioAndAwaitAck, pollAgentSessionEvents, pushAgentSessionEvent, } from "./agentSessionChannel.js";
const SERVICE_URL = "https://test.invalid";
const API_KEY = "key-test";
const SESSION_ID = "11111111-1111-4111-8111-111111111111";
function makeNavigateEvent(id, path) {
    return { id, type: "agent:navigate", data: { path } };
}
function jsonResponse(body, init) {
    return new Response(JSON.stringify(body), {
        status: 200,
        headers: { "Content-Type": "application/json" },
        ...init,
    });
}
describe("createAgentSession", () => {
    let fetchMock;
    const originalFetch = globalThis.fetch;
    beforeEach(() => {
        fetchMock = vi.fn();
        globalThis.fetch = fetchMock;
    });
    afterEach(() => {
        globalThis.fetch = originalFetch;
    });
    it("POSTs to /api/studio/sessions with bearer auth", async () => {
        fetchMock.mockResolvedValueOnce(jsonResponse({ ok: true, sessionId: SESSION_ID }));
        const result = await createAgentSession({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
        });
        expect(result).toEqual({ ok: true, sessionId: SESSION_ID });
        const [calledUrl, init] = fetchMock.mock.calls[0];
        expect(calledUrl).toBe(`${SERVICE_URL}/api/studio/sessions`);
        expect(init.headers.Authorization).toBe(`Bearer ${API_KEY}`);
        expect(JSON.parse(init.body)).toEqual({
            sessionId: SESSION_ID,
        });
    });
    it("includes extraHeaders in the request", async () => {
        fetchMock.mockResolvedValueOnce(jsonResponse({ ok: true, sessionId: SESSION_ID }));
        await createAgentSession({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            extraHeaders: {
                "x-bitfab-client-name": "cursor",
                "x-bitfab-client-display-name": "Cursor",
            },
        });
        const [, init] = fetchMock.mock.calls[0];
        const headers = init.headers;
        expect(headers["x-bitfab-client-name"]).toBe("cursor");
        expect(headers["x-bitfab-client-display-name"]).toBe("Cursor");
    });
    it("throws on non-2xx", async () => {
        fetchMock.mockResolvedValueOnce(new Response("forbidden", { status: 403 }));
        await expect(createAgentSession({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
        })).rejects.toThrow(/403/);
    });
});
describe("pushAgentSessionEvent", () => {
    let fetchMock;
    const originalFetch = globalThis.fetch;
    beforeEach(() => {
        fetchMock = vi.fn();
        globalThis.fetch = fetchMock;
    });
    afterEach(() => {
        globalThis.fetch = originalFetch;
    });
    it("POSTs to /api/studio/events with bearer auth and the session payload", async () => {
        fetchMock.mockResolvedValueOnce(jsonResponse({ id: "1735689600000-0" }));
        const result = await pushAgentSessionEvent({ serviceUrl: SERVICE_URL, apiKey: API_KEY, sessionId: SESSION_ID }, { type: "agent:navigate", data: { path: "/traces/abc" } });
        expect(result).toEqual({ id: "1735689600000-0" });
        const [calledUrl, init] = fetchMock.mock.calls[0];
        expect(calledUrl).toBe(`${SERVICE_URL}/api/studio/events`);
        expect(init.headers.Authorization).toBe(`Bearer ${API_KEY}`);
        expect(JSON.parse(init.body)).toEqual({
            session: SESSION_ID,
            type: "agent:navigate",
            data: { path: "/traces/abc" },
        });
    });
    it("throws on non-2xx", async () => {
        fetchMock.mockResolvedValueOnce(new Response("forbidden", { status: 403 }));
        await expect(pushAgentSessionEvent({ serviceUrl: SERVICE_URL, apiKey: API_KEY, sessionId: SESSION_ID }, { type: "agent:navigate", data: { path: "/x" } })).rejects.toThrow(/403/);
    });
});
