describe("pollAgentSessionEvents", () => {
    let fetchMock;
    const originalFetch = globalThis.fetch;
    beforeEach(() => {
        fetchMock = vi.fn();
        globalThis.fetch = fetchMock;
        vi.useFakeTimers();
    });
    afterEach(() => {
        globalThis.fetch = originalFetch;
        vi.useRealTimers();
    });
    it("emits events and advances the cursor across polls", async () => {
        const e1 = makeNavigateEvent("1735689600000-0", "/a");
        const e2 = makeNavigateEvent("1735689600001-0", "/b");
        fetchMock
            .mockResolvedValueOnce(jsonResponse({ events: [e1, e2] }))
            .mockResolvedValueOnce(jsonResponse({ events: [] }));
        const events = [];
        const abort = new AbortController();
        const loop = pollAgentSessionEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            intervalMs: 100,
            abortSignal: abort.signal,
            onEvent: (event) => events.push(event),
        });
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(100);
        await vi.advanceTimersByTimeAsync(0);
        abort.abort();
        await loop;
        expect(events).toEqual([e1, e2]);
        expect(fetchMock).toHaveBeenCalledTimes(2);
        const firstUrl = fetchMock.mock.calls[0][0];
        const secondUrl = fetchMock.mock.calls[1][0];
        expect(firstUrl).toContain(`session=${SESSION_ID}`);
        expect(firstUrl).not.toContain("since=");
        expect(secondUrl).toContain(`since=${encodeURIComponent(e2.id)}`);
    });
    it("invokes onBrowserStatus when browserConnected is in the response", async () => {
        fetchMock
            .mockResolvedValueOnce(jsonResponse({ events: [], browserConnected: true }))
            .mockResolvedValueOnce(jsonResponse({ events: [], browserConnected: false }));
        const statuses = [];
        const abort = new AbortController();
        const loop = pollAgentSessionEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            intervalMs: 50,
            abortSignal: abort.signal,
            onEvent: () => { },
            onBrowserStatus: (connected) => statuses.push(connected),
        });
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(50);
        await vi.advanceTimersByTimeAsync(0);
        abort.abort();
        await loop;
        expect(statuses).toEqual([true, false]);
    });
    it("respects startCursor on the first fetch", async () => {
        const start = "1735689600000-0";
        fetchMock.mockResolvedValueOnce(jsonResponse({ events: [] }));
        const abort = new AbortController();
        const loop = pollAgentSessionEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            startCursor: start,
            abortSignal: abort.signal,
            onEvent: () => { },
        });
        await vi.advanceTimersByTimeAsync(0);
        abort.abort();
        await loop;
        const firstUrl = fetchMock.mock.calls[0][0];
        expect(firstUrl).toContain(`since=${encodeURIComponent(start)}`);
    });
    it("calls onError on non-2xx responses but keeps looping", async () => {
        fetchMock
            .mockResolvedValueOnce(jsonResponse({ error: "boom" }, { status: 500 }))
            .mockResolvedValueOnce(jsonResponse({ events: [] }));
        const errors = [];
        const abort = new AbortController();
        const loop = pollAgentSessionEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            intervalMs: 50,
            abortSignal: abort.signal,
            onEvent: () => { },
            onError: (err) => errors.push(err),
        });
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(50);
        await vi.advanceTimersByTimeAsync(0);
        abort.abort();
        await loop;
        expect(errors).toHaveLength(1);
        expect(errors[0].message).toMatch(/500/);
        expect(fetchMock).toHaveBeenCalledTimes(2);
    });
    it("terminates immediately when abort fires before the first fetch", async () => {
        const abort = new AbortController();
        abort.abort();
        const loop = pollAgentSessionEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            abortSignal: abort.signal,
            onEvent: () => { },
        });
        await loop;
        expect(fetchMock).not.toHaveBeenCalled();
    });
    it("sends the API key as a Bearer Authorization header", async () => {
        fetchMock.mockResolvedValueOnce(jsonResponse({ events: [] }));
        const abort = new AbortController();
        const loop = pollAgentSessionEvents({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
            abortSignal: abort.signal,
            onEvent: () => { },
        });
        await vi.advanceTimersByTimeAsync(0);
        abort.abort();
        await loop;
        const init = fetchMock.mock.calls[0][1];
        expect(init.headers.Authorization).toBe(`Bearer ${API_KEY}`);
    });
});
describe("navigateStudioAndAwaitAck", () => {
    let fetchMock;
    const originalFetch = globalThis.fetch;
    beforeEach(() => {
        fetchMock = vi.fn();
        globalThis.fetch = fetchMock;
        vi.useFakeTimers();
    });
    afterEach(() => {
        globalThis.fetch = originalFetch;
        vi.useRealTimers();
    });
    // Mock ordering note: `navigateStudioAndAwaitAck` starts the poll loop
    // INSIDE the Promise constructor (sync), then awaits the navigate POST
    // after the constructor returns. So the first fetch dispatched is the
    // poll's GET, and the second is the navigate's POST. Order the mocks
    // accordingly.
    it("resolves acked: true when studio:navigated arrives for the matching path", async () => {
        const path = "/studio/trace-plan/abc";
        fetchMock
            // First fetch: poll GET — returns the matching studio:navigated ack.
            .mockResolvedValueOnce(jsonResponse({
            events: [
                { id: "1735689600000-0", type: "studio:navigated", data: { path } },
            ],
        }))
            // Second fetch: navigate POST.
            .mockResolvedValueOnce(jsonResponse({ id: "evt-1" }));
        const promise = navigateStudioAndAwaitAck({ serviceUrl: SERVICE_URL, apiKey: API_KEY, sessionId: SESSION_ID }, path, { ackTimeoutMs: 5_000 });
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        await expect(promise).resolves.toEqual({ acked: true });
    });
    it("resolves acked: false / session-ended when the tab closes mid-wait", async () => {
        const path = "/studio/trace-plan/abc";
        fetchMock
            .mockResolvedValueOnce(jsonResponse({
            events: [
                { id: "1735689600000-0", type: "studio:session-ended", data: {} },
            ],
        }))
            .mockResolvedValueOnce(jsonResponse({ id: "evt-1" }));
        const promise = navigateStudioAndAwaitAck({ serviceUrl: SERVICE_URL, apiKey: API_KEY, sessionId: SESSION_ID }, path, { ackTimeoutMs: 5_000 });
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        await expect(promise).resolves.toEqual({
            acked: false,
            reason: "session-ended",
        });
    });
    it("resolves acked: false / timeout when no ack arrives before the deadline", async () => {
        const path = "/studio/trace-plan/abc";
        // Polls keep returning empty events; navigate POST returns ok. Use
        // mockImplementation so each call gets a fresh Response (Response
        // bodies can only be consumed once — mockResolvedValue would hand the
        // same Response to both the poll GET and the navigate POST, causing
        // the second .json() call to throw).
        fetchMock.mockImplementation(() => jsonResponse({ events: [] }));
        const promise = navigateStudioAndAwaitAck({ serviceUrl: SERVICE_URL, apiKey: API_KEY, sessionId: SESSION_ID }, path, { ackTimeoutMs: 1_000 });
        // Drain the navigate push + the first poll cycle, then jump past the
        // ack deadline.
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(0);
        await vi.advanceTimersByTimeAsync(1_001);
        await expect(promise).resolves.toEqual({
            acked: false,
            reason: "timeout",
        });
    });
    it("resolves acked: false / push-failed when the navigate POST throws", async () => {
        const path = "/studio/trace-plan/abc";
        fetchMock.mockRejectedValueOnce(new Error("network down"));
        const promise = navigateStudioAndAwaitAck({ serviceUrl: SERVICE_URL, apiKey: API_KEY, sessionId: SESSION_ID }, path, { ackTimeoutMs: 5_000 });
        await vi.advanceTimersByTimeAsync(0);
        await expect(promise).resolves.toEqual({
            acked: false,
            reason: "push-failed",
        });
    });
});
describe("isStudioBrowserConnected", () => {
    let fetchMock;
    const originalFetch = globalThis.fetch;
    beforeEach(() => {
        fetchMock = vi.fn();
        globalThis.fetch = fetchMock;
    });
    afterEach(() => {
        globalThis.fetch = originalFetch;
    });
    it("returns true when the server reports browserConnected", async () => {
        fetchMock.mockResolvedValueOnce(jsonResponse({ events: [], browserConnected: true }));
        const got = await isStudioBrowserConnected({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
        });
        expect(got).toBe(true);
    });
    it("returns false when browserConnected is missing or false", async () => {
        fetchMock.mockResolvedValueOnce(jsonResponse({ events: [] }));
        const got = await isStudioBrowserConnected({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
        });
        expect(got).toBe(false);
    });
    it("returns false on non-2xx", async () => {
        fetchMock.mockResolvedValueOnce(jsonResponse({ error: "forbidden" }, { status: 403 }));
        const got = await isStudioBrowserConnected({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
        });
        expect(got).toBe(false);
    });
    it("returns false when the fetch throws", async () => {
        fetchMock.mockRejectedValueOnce(new Error("network down"));
        const got = await isStudioBrowserConnected({
            serviceUrl: SERVICE_URL,
            apiKey: API_KEY,
            sessionId: SESSION_ID,
        });
        expect(got).toBe(false);
    });
});
